Bash(node -e 'const http = require\("http"\); 
const url = "https://served-photos-556758165742-us-west-2-an.s3.us-west-2.amazonaws.com/gallery/DSC06374.jpg";
console.log\(`Testing accessibility of: ${url}...`\);
http.get\(url, \(res\) => {
  console.log\(`Response Status: ${res.statusCode}`\);
  if \(res.statusCode === 200\) {
    console.log\("✅ SUCCESS: Image is publicly accessible."\);
  } else if \(res.statusCode === 403\) {
    console.error\("❌ FAILURE: 403 Forbidden. The S3 bucket is NOT public. You need to update the Bucket Policy and ACLs."\);
  } else if \(res.statusCode === 404\) {
    console.error\("❌ FAILURE: 404 Not Found. The file does not exist at this path."\);
  } else {
    console.error\(`❌ FAILURE: Received unexpected status code ${res.statusCode}`\);
  }
  process.exit\(0\);
}\).on\("error", \(err\) => {
  console.error\(`❌ FAILURE: Network error: ${err.message}`\);
  process.exit\(1\);
}\);')

